def process_debt_score(company):
    score = 0
    if company.get("age_years", 0) > 10:
        score += 25
    if company.get("data_scattered_across_tools", 0) >= 5:
        score += 20
    if company.get("tacit_knowledge_pct", 0) > 50:
        score += 20
    if company.get("paper_processes", 0) > 0:
        score += 15
    if company.get("headcount_per_revenue_million", 0) > 7:
        score += 10
    if company.get("documented_workflows_pct", 100) < 30:
        score += 10
    if score <= 20:
        verdict = "AI-native ready"
    elif score <= 50:
        verdict = "manageable debt"
    elif score <= 80:
        verdict = "heavy debt"
    else:
        verdict = "incumbent trap"
    return {"score": score, "verdict": verdict}

print(f"HVAC Inc:   {process_debt_score(hvac_inc)}")
print(f"StartupCo:  {process_debt_score(startup_co)}")

